// Captura a resposta bruta da Gemini
let resposta = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || "";

// Normaliza
resposta = String(resposta)
  .trim()
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

// ---------------------------------------------------
// Função para extrair o JSON principal (objeto)
// ---------------------------------------------------
function extrairJsonObjeto(texto) {
  const start = texto.indexOf("{");
  const end = texto.lastIndexOf("}");

  if (start !== -1 && end !== -1 && end > start) {
    return texto.substring(start, end + 1);
  }

  return null;
}

const jsonBruto = extrairJsonObjeto(resposta);

if (!jsonBruto) {
  return [{
    json: {
      sucesso: false,
      erro: "❌ Nenhum objeto JSON encontrado na resposta",
      respostaBruta: resposta
    }
  }];
}

try {
  const parsed = JSON.parse(jsonBruto);

  // garante objeto
  if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
    return [{
      json: {
        sucesso: false,
        erro: "❌ O JSON retornado não é um objeto no formato esperado",
        jsonExtraido: jsonBruto,
        respostaBruta: resposta
      }
    }];
  }

  const tipoRelatorio = parsed.tipoRelatorio ?? null;
  const arquivo = parsed.arquivo ?? null;

  const periodoInicio = parsed.periodo?.inicio ?? null;
  const periodoFim = parsed.periodo?.fim ?? null;

  const numeroPacientesListados = parsed.totais?.numeroPacientesListados ?? null;
  const numeroExamesEfetuados = parsed.totais?.numeroExamesEfetuados ?? null;
  const valorFaturadoTotal = parsed.totais?.valorFaturadoTotal ?? null;

  const dataImpressao = parsed.impressao?.dataImpressao ?? null;
  const usuario = parsed.impressao?.usuario ?? null;

  const registros = Array.isArray(parsed.registros) ? parsed.registros : [];

  // Se houver registros, retorna 1 item por registro
  if (registros.length > 0) {
    return registros.map((registro, idx) => ({
      json: {
        sucesso: true,

        // metadados do relatório
        tipoRelatorio,
        arquivo,

        // período
        periodoInicio,
        periodoFim,

        // totais
        numeroPacientesListados,
        numeroExamesEfetuados,
        valorFaturadoTotal,

        // impressão
        dataImpressao,
        usuario,

        // dados do registro
        posto: registro.posto ?? null,
        local: registro.local ?? null,
        req: registro.req ?? null,
        exames: registro.exames ?? null,
        valor: registro.valor ?? null,
        area: registro.area ?? null,
        responsavel: registro.responsavel ?? null,

        // apoio/debug
        _idx: idx + 1,
        _totalRegistros: registros.length
      }
    }));
  }

  // Se não houver registros, retorna o objeto consolidado
  return [{
    json: {
      sucesso: true,
      categoria: "(+)COMPUTADOR DO POSTO",
      tipoRelatorio,
      arquivo,
      periodoInicio,
      periodoFim,
      numeroPacientesListados,
      numeroExamesEfetuados,
      valorFaturadoTotal,
      dataImpressao,
      usuario,
      registros: [],
      _totalRegistros: 0
    }
  }];

} catch (e) {
  return [{
    json: {
      sucesso: false,
      erro: "❌ JSON encontrado, mas inválido",
      mensagem: e.message,
      jsonExtraido: jsonBruto,
      respostaBruta: resposta
    }
  }];
}

