let texto = String(conteudoBruto)
  .replace(/\r\n/g, "\n")
  .replace(/\r/g, "\n")
  .replace(/"/g, "'")
  .replace(/[\u0000-\u001F\u007F-\u009F]/g, " ")
  .replace(/\t/g, " ")
  .replace(/[ ]{2,}/g, " ")
  .replace(/\n[ ]+/g, "\n")
  .replace(/[ ]+\n/g, "\n")
  .trim();

// -------------------------
// 2) limpeza leve e segura
// -------------------------
function normalizarOcrRelatorio(s) {
  let t = s;

  // normalizações comuns de OCR
  t = t.replace(/ÁREAO\s*([0-9]{1,2})/gi, "ÁREA $1");
  t = t.replace(/ÁREAO([0-9]{1,2})/gi, "ÁREA $1");
  t = t.replace(/AMAUR\|I/gi, "AMAURI");

  // corrige cabeçalho comum
  t = t.replace(/Posto\s+Local\s+Req\.?\s+Exames\s+[—-]?\s*Valor/gi, "Posto Local Req. Exames Valor");

  // remove duplicidade excessiva de espaços
  t = t.replace(/[ ]{2,}/g, " ").trim();

  return t;
}

const conteudoLimpo = normalizarOcrRelatorio(texto);

